-- Verify (book categories — Garden & Sips seeded separately)
SELECT category, count(*) FILTER (WHERE kind = 'sub') AS subs,
       count(*) FILTER (WHERE kind = 'div') AS divisions
FROM (
  SELECT category, 'sub' AS kind FROM public.recipe_subcategories
  WHERE is_active = true AND category NOT IN ('Sips & Stories', 'Garden & Earth')
  UNION ALL
  SELECT category, 'div' FROM public.recipe_divisions
  WHERE is_active = true AND category NOT IN ('Sips & Stories', 'Garden & Earth')
) t
GROUP BY category
ORDER BY category;
